import { useEffect, useState } from "react";
import API from "../services/api";

function Standings() {
  const [data, setData] = useState({ standings: [], stats: {} });
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchStandings = async () => {
      try {
        setLoading(true);
        const res = await API.get("/matches/standings");
        setData(res.data);
      } catch (err) {
        console.error("Error fetching standings:", err);
        setError(err.response?.data?.message || err.message);
      } finally {
        setLoading(false);
      }
    };

    fetchStandings();
  }, []);

  if (loading) return <div className="page"><p>Loading standings...</p></div>;
  if (error) return <div className="page"><p style={{ color: "red" }}>Error: {error}</p></div>;

  const { standings, stats } = data;

  return (
    <div className="page">
      <h2>Tournament Stats & Standings</h2>

      {/* Highlights Section */}
      <div className="stats-highlights" style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '20px', marginBottom: '30px' }}>
        <div className="standings-container" style={{ margin: 0, padding: '15px', textAlign: 'center' }}>
          <h4 style={{ margin: '0 0 10px 0', color: '#999', fontSize: '0.8rem', textTransform: 'uppercase' }}>Highest Team Score</h4>
          <p style={{ fontSize: '1.2rem', fontWeight: '800', margin: 0, color: 'var(--cyan)' }}>{stats.highestTeamScore?.score || 0}</p>
          <p style={{ fontSize: '0.8rem', margin: '5px 0 0 0', opacity: 0.8 }}>{stats.highestTeamScore?.team} vs {stats.highestTeamScore?.against}</p>
        </div>
        <div className="standings-container" style={{ margin: 0, padding: '15px', textAlign: 'center' }}>
          <h4 style={{ margin: '0 0 10px 0', color: '#999', fontSize: '0.8rem', textTransform: 'uppercase' }}>Most Runs</h4>
          <p style={{ fontSize: '1.2rem', fontWeight: '800', margin: 0, color: '#00ff88' }}>{stats.mostRuns?.runs || 0}</p>
          <p style={{ fontSize: '0.8rem', margin: '5px 0 0 0', opacity: 0.8 }}>{stats.mostRuns?.player}</p>
        </div>
        <div className="standings-container" style={{ margin: 0, padding: '15px', textAlign: 'center' }}>
          <h4 style={{ margin: '0 0 10px 0', color: '#999', fontSize: '0.8rem', textTransform: 'uppercase' }}>Most Wickets</h4>
          <p style={{ fontSize: '1.2rem', fontWeight: '800', margin: 0, color: '#ff4d4d' }}>{stats.mostWickets?.wickets || 0}</p>
          <p style={{ fontSize: '0.8rem', margin: '5px 0 0 0', opacity: 0.8 }}>{stats.mostWickets?.player}</p>
        </div>
        <div className="standings-container" style={{ margin: 0, padding: '15px', textAlign: 'center' }}>
          <h4 style={{ margin: '0 0 10px 0', color: '#999', fontSize: '0.8rem', textTransform: 'uppercase' }}>Best Individual Score</h4>
          <p style={{ fontSize: '1.2rem', fontWeight: '800', margin: 0, color: '#ffc107' }}>{stats.bestIndividualScore?.runs || 0}</p>
          <p style={{ fontSize: '0.8rem', margin: '5px 0 0 0', opacity: 0.8 }}>{stats.bestIndividualScore?.player} ({stats.bestIndividualScore?.team})</p>
        </div>
        <div className="standings-container" style={{ margin: 0, padding: '15px', textAlign: 'center' }}>
          <h4 style={{ margin: '0 0 10px 0', color: '#999', fontSize: '0.8rem', textTransform: 'uppercase' }}>Best Bowling Figure</h4>
          <p style={{ fontSize: '1.2rem', fontWeight: '800', margin: 0, color: '#e91e63' }}>{stats.bestBowlingFigure?.wickets || 0} Wkts</p>
          <p style={{ fontSize: '0.8rem', margin: '5px 0 0 0', opacity: 0.8 }}>{stats.bestBowlingFigure?.player} ({stats.bestBowlingFigure?.team})</p>
        </div>
      </div>

      <div className="standings-container">
        <div style={{ overflowX: 'auto' }}>
          <table className="standings-table">
            <thead>
              <tr>
                <th>Team</th>
                <th>P</th>
                <th>W</th>
                <th>L</th>
                <th>T</th>
                <th>Pts</th>
              </tr>
            </thead>
            <tbody>
              {standings.map((row, index) => (
                <tr key={index}>
                  <td className="team-name">{row.team}</td>
                  <td>{row.played}</td>
                  <td>{row.won}</td>
                  <td>{row.lost}</td>
                  <td>{row.tied}</td>
                  <td className="points-cell">{row.points}</td>
                </tr>
              ))}
              {standings.length === 0 && (
                <tr>
                  <td colSpan="6" style={{ padding: '20px', textAlign: 'center', color: '#999' }}>
                    No match data available to calculate standings.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

export default Standings;
